class Solution:
    def minCost(self, m, n, waitCost):
        import sys
        sys.setrecursionlimit(300000)
        from functools import lru_cache
        def entry(i, j):
            return (i + 1) * (j + 1)
        # best[i][j] = min cost to enter (i,j)
        best = [[None] * n for _ in range(m)]
        best[0][0] = entry(0, 0)
        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                cands = []
                if i > 0:
                    base = best[i - 1][j]
                    w = 0 if (i - 1 == 0 and j == 0) else waitCost[i - 1][j]
                    cands.append(base + w)
                if j > 0:
                    base = best[i][j - 1]
                    w = 0 if (i == 0 and j - 1 == 0) else waitCost[i][j - 1]
                    cands.append(base + w)
                best[i][j] = min(cands) + entry(i, j)
        return best[m - 1][n - 1]

