class Solution:
    def minCost(self, m, n, waitCost):
        INF = float('inf')
        dp = [[INF] * n for _ in range(m)]
        dp[0][0] = 1
        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                e = (i + 1) * (j + 1)
                best = INF
                if i > 0:
                    w = 0 if (i - 1 == 0 and j == 0) else waitCost[i - 1][j]
                    best = min(best, dp[i - 1][j] + w)
                if j > 0:
                    w = 0 if (i == 0 and j - 1 == 0) else waitCost[i][j - 1]
                    best = min(best, dp[i][j - 1] + w)
                dp[i][j] = best + e
        return dp[m - 1][n - 1]

