var minCost = function(m, n, waitCost) {
    const INF = Infinity;
    const dp = Array.from({length: m}, () => new Array(n).fill(INF));
    dp[0][0] = 1;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (i === 0 && j === 0) continue;
            const e = (i + 1) * (j + 1);
            let best = INF;
            if (i > 0) {
                const w = (i - 1 === 0 && j === 0) ? 0 : waitCost[i - 1][j];
                best = Math.min(best, dp[i - 1][j] + w);
            }
            if (j > 0) {
                const w = (i === 0 && j - 1 === 0) ? 0 : waitCost[i][j - 1];
                best = Math.min(best, dp[i][j - 1] + w);
            }
            dp[i][j] = best + e;
        }
    }
    return dp[m - 1][n - 1];
};
